def filter_outlier_orders(orders: list[dict], is_buy_order: bool) -> list[dict]:
    """Filter outlier orders based on price deviation from median."""
    relevant = [o for o in orders if o.get('is_buy_order') == is_buy_order]
    if not relevant:
        return relevant

    prices = [o['price'] for o in relevant]
    prices.sort()
    n = len(prices)

    median = prices[n // 2] if n % 2 == 1 else (prices[n // 2 - 1] + prices[n // 2]) / 2

    if is_buy_order:
        threshold = median * 1.1
        return [o for o in relevant if o['price'] <= threshold]
    else:
        threshold = median * 10
        return [o for o in relevant if o['price'] <= threshold]


def calculate_volume_weighted_average_price(orders: list[dict]) -> float:
    """Calculate volume-weighted average price. Returns 0.0 for empty list."""
    if not orders:
        return 0.0

    total_volume = sum(o['volume_remain'] for o in orders)
    if total_volume == 0:
        return 0.0

    weighted_sum = sum(o['price'] * o['volume_remain'] for o in orders)
    return weighted_sum / total_volume

